function getCustomParamsWithEmail() {
  const contactList = $input.first().json.contact_list[0];
  const results = [];

  if (Array.isArray(contactList)) {
    contactList.forEach(contact => {
      // 檢查 customParams 是否包含 email
      const hasEmail = contact.customParams.some(param => param.name === "email");
      //import PROD data ONLY
      const isPROD = contact.customParams.some(param => param.name === "env" && param.value === "prod");

      // 如果包含 email，則創建一個對象並添加到 results
      if (hasEmail && isPROD) {
        const customParamsObject = {};

        // 將 customParams 轉換為對象
        contact.customParams.forEach(param => {
          customParamsObject[param.name] = param.value;
        });

        results.push(customParamsObject);
      }
    });
  } else {
    console.error("contact_list[0] is not an array", contactList);
  }

  return results;
}

// 呼叫函數並返回結果
return getCustomParamsWithEmail();

